// Evidence: httpsts-worked-http-server-ts-authorization-tenancy-5
// Competency: httpsts-worked-http-server-ts-authorization-tenancy-5.
// Case 9036: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: saturate one tenant budget while another tenant remains serviceable.
function worked_http_server_ts_authorization_tenancy_5(subjectTenant: string, resourceTenant: string, action: string, propertyAllowed: boolean): { allowed: boolean; reason: string } {
  if (subjectTenant.length === 0 || subjectTenant !== resourceTenant) {
    return { allowed: false, reason: "tenant-denied" };
  }
  if (action !== "read" && action !== "update") return { allowed: false, reason: "function-denied" };
  if (!propertyAllowed) return { allowed: false, reason: "property-denied" };
  return { allowed: true, reason: "resource-policy" };
}

